#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=3e5+10;int head[N],des[N<<1],nxt[N<<1],cgt,n,Q,t[N],ans[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
struct SEG
{
	struct Seg{int l,r,sz;}t[N*28];int Rt[N],cnt;
	inline void add(int &x,int pos,int w,int l=-10,int r=(n*2)+10)
	{
		if(!x)x=++cnt;if(l==r){t[x].sz+=w;return;} int mid=(l+r)>>1;
		pos<=mid?add(t[x].l,pos,w,l,mid):add(t[x].r,pos,w,mid+1,r);
	}
	inline int qry(int cur,int pos,int l=-10,int r=(n*2)+10)
	{
		if(!cur)return 0;if(l==r)return t[cur].sz;int mid=(l+r)>>1;
		return pos<=mid?qry(t[cur].l,pos,l,mid):qry(t[cur].r,pos,mid+1,r);
	}
	inline int merge(int x,int y,int l=-10,int r=(n*2+10))
	{
		if(!x||!y)return x|y;if(l==r){t[x].sz+=t[y].sz;return x;}int mid=(l+r)>>1;
		t[x].l=merge(t[x].l,t[y].l,l,mid);t[x].r=merge(t[x].r,t[y].r,mid+1,r);t[x].sz+=t[y].sz;return x;
	}
	inline int& operator [] (const int &x){return Rt[x];}
}D,U;
namespace TreeCut
{
	int top[N],siz[N],dep[N],mxs[N],fa[N];
	inline void dfs1(const int &u=1,const int &f=0)
	{
		siz[u]=1;dep[u]=dep[fa[u]=f]+1;int mx=0;
		grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
	}
	inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
	{
		top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
		grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);
	}
	inline int LCA(int u,int v)
	{
		while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
		return dep[u] < dep[v] ? u : v ;
	}
}
using TreeCut::LCA;using TreeCut::dep;using TreeCut::fa;
inline void dfs(const int &u=1,const int &fa=0)
{
	grep(u,i)if(des[i]!=fa){int v=des[i];dfs(v,u);D[u]=D.merge(D[u],D[v]);U[u]=U.merge(U[u],U[v]);}
	ans[u]=D.qry(D[u],t[u]-dep[u]+n)+U.qry(U[u],t[u]+dep[u]);
}
//Up :: t+dep  ||  Down:: t-dep+n
int main()
{
	n=read();Q=read();rep(2,n,i)ins(read(),read());rep(1,n,i)t[i]=read();
	TreeCut::dfs1();TreeCut::dfs2(); while(Q--)
	{
		int u=read(),v=read(),lc=LCA(u,v);U.add(U[u],dep[u],1);U.add(U[lc],dep[u],-1);
		int tt=dep[u]-dep[lc];D.add(D[v],tt+n-dep[lc],1);if(fa[lc])D.add(D[fa[lc]],tt+n-dep[lc],-1);
	}
	dfs();rep(1,n,i)print(ans[i]),putchar(' ');putchar('\n');return 0;
}
